#include "hcsr04.h"
#include <Arduino.h>
#define TRIG 5
#define ECHO 18
static float _dist=0;
static unsigned long _last=0;
void hcsr04_setup(){pinMode(TRIG,OUTPUT);pinMode(ECHO,INPUT);Serial.println("[hcsr04] OK");}
void hcsr04_loop(){
  if(millis()-_last<100)return;
  _last=millis();
  digitalWrite(TRIG,LOW);delayMicroseconds(2);
  digitalWrite(TRIG,HIGH);delayMicroseconds(10);
  digitalWrite(TRIG,LOW);
  long dur=pulseIn(ECHO,HIGH,30000);
  _dist=dur*0.0343/2.0;
  if(_dist>0&&_dist<400)Serial.printf("[hcsr04] %.1fcm\n",_dist);
}
float hcsr04_get_distance_cm(){return _dist;}
